import java.util.*;

public class OmaRedirectLinkBuilder {

    // Field-like constants per the prompt
    public static final String OMA_REDIRECT_LINK = "omaredirect.do";
    public static final String SITE_PARAM = "path";

    // Core: create the full Oma redirect link from a parameter map
    public static String createOmaLink(Map<String,String> paramMap) {
        if (paramMap == null) {
            paramMap = new LinkedHashMap<>();
        }
        // Ensure path is present
        if (!paramMap.containsKey("path")) {
            paramMap.put("path","/");
        }
        String query = createQueryString(paramMap);
        return OMA_REDIRECT_LINK + "?" + query;
    }

    // Core: create the query string in a stable order: path, cm, var, fts
    public static String createQueryString(Map<String,String> paramMap) {
        StringBuilder sb = new StringBuilder();
        // path
        String pathVal = paramMap.get("path");
        if (pathVal == null) pathVal = "/";
        sb.append("path=").append(pathVal);

        // other known keys in a deterministic order
        String[] keys = new String[] { "cm", "var", "fts" };
        for (String k : keys) {
            String v = paramMap.get(k);
            if (v != null) {
                sb.append('&').append(k).append('=').append(v);
            }
        }
        return sb.toString();
    }

    // Remove path parameter from a query string (if needed)
    public static String removePath(String query) {
        if (query == null || query.isEmpty()) return query;
        String[] parts = query.split("&");
        StringBuilder sb = new StringBuilder();
        boolean first = true;
        for (String p : parts) {
            if (p.startsWith("path=")) continue;
            if (!first) sb.append('&');
            sb.append(p);
            first = false;
        }
        return sb.toString();
    }

    // If not absolute, prepend http://
    public static String conditionallyPrependHttp(String url) {
        if (url == null || url.isEmpty()) return url;
        if (url.startsWith("http://") || url.startsWith("https://")) {
            return url;
        }
        return "http://" + url;
    }

    // Parse incoming query string into a map (preserving order where possible)
    public static HashMap<String,String> getParameterMap(String incomingQuery) {
        HashMap<String,String> map = new LinkedHashMap<>();
        if (incomingQuery == null) return map;
        String q = incomingQuery;
        if (q.startsWith("?")) q = q.substring(1);
        String[] parts = q.split("&");
        for (String p : parts) {
            int eq = p.indexOf('=');
            if (eq <= 0) continue;
            String key = p.substring(0, eq);
            String val = p.substring(eq + 1);
            map.put(key, val);
        }
        return map;
    }

    // Return the list of keys in a stable order
    public static ArrayList<String> getKeyList() {
        return new ArrayList<>(Arrays.asList("path","cm","var","fts"));
    }

    // Delimiter used between parameters (if needed)
    public static String getDelimiter() {
        return "&";
    }

    // Example usage (not required, but illustrative)
    public static void main(String[] args) {
        // incoming: http://mutationassessor.org/?cm=var&var=17,7517830,g,c&fts=all
        String incoming = "cm=var&var=17,7517830,g,c&fts=all";
        HashMap<String,String> params = getParameterMap(incoming);

        // Ensure path and construct the outgoing link
        String omaLink = createOmaLink(params);
        System.out.println(omaLink);
        // Example output: omaredirect.do?path=/&cm=var&var=17,7517830,g,c&fts=all
    }
}
